export const handler = (input) => {
  const baseLimit = Math.max(500000, 0.10 * input.tier1_capital);
  const applicable_limit = input.has_collateral_backing ? baseLimit * 1.5 : baseLimit;
  const headroom = applicable_limit - input.insider_loan_amount;
  const breach = input.insider_loan_amount > applicable_limit;
  return {
    breach: breach,
    applicable_limit: applicable_limit,
    headroom: headroom
  };
};
